package com.user.servlet;
import com.DB.DBConnect; import com.DAO.UserDAOImpl; import com.entity.User; import javax.servlet.*; import javax.servlet.annotation.WebServlet; import javax.servlet.http.*; import java.io.*;
@WebServlet("/register") public class RegisterServlet extends HttpServlet { protected void doPost(HttpServletRequest req,HttpServletResponse resp)throws IOException { req.setCharacterEncoding("UTF-8"); HttpSession s=req.getSession(); String name=req.getParameter("fname"),email=req.getParameter("email"),phone=req.getParameter("phono"),pass=req.getParameter("password"),check=req.getParameter("check"); if(check==null){s.setAttribute("failedMsg","Please accept terms and conditions");resp.sendRedirect("register.jsp");return;} try(var c=DBConnect.getConn()){UserDAOImpl dao=new UserDAOImpl(c); if(dao.checkUser(email)){s.setAttribute("failedMsg","Email already exists");} else {User u=new User();u.setName(name);u.setEmail(email);u.setPhono(phone);u.setPassword(pass);u.setAddress("");u.setLandmark("");u.setCity("");u.setState("");u.setPincode("");boolean saved=dao.userRegister(u); s.setAttribute(saved?"succMsg":"failedMsg",saved?"Registration successful":"Registration failed");}}catch(Exception e){s.setAttribute("failedMsg",e.getMessage());} resp.sendRedirect("register.jsp"); }}
